/* HTML:
  <div id="parent" style="padding: 50px; background: blue;">
    <button id="child">Click Me</button>
  </div>
*/

document.getElementById('parent').addEventListener('click', () => {
  console.log('Parent click listener fired!');
});

document.getElementById('child').addEventListener('click', () => {
  console.log('Child click listener fired!');
});

// If you click the button, you will see:
// 1. 'Child click listener fired!'
// 2. 'Parent click listener fired!' (Because of Bubbling)
